using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 removed "Discriminator" property.
            // Existing documents still have it, so map it explicitly to avoid losing data.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Preserve the old format so existing documents remain readable.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change 3: Cosmos DB does not support indexes defined via EF Core.
            // HasIndex() now throws at model validation time in EF 9. Removed.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }

    // Breaking change 1 (cont.): materialize the discriminator so raw SQL still works
    // e.g. SELECT * FROM c WHERE c.Discriminator = 'Blog'
    public string Discriminator { get; set; }
}

// Breaking change 2 (cont.): value generator that reproduces the EF 8 "Discriminator|Key" id format
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;
class LegacyIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
    {
        var key = entry.Property("Id").CurrentValue?.ToString()
                  ?? Guid.NewGuid().ToString();
        return $"{entry.Metadata.ShortName()}|{key}";
    }
}

